async function getSketchJson(imageId, teamId, projectId) {
  const documentInfo = await getDesignDocument(imageId, teamId, projectId);
  const latestVersion = Array.isArray(documentInfo?.versions) ? documentInfo.versions[0] : null;
  const jsonUrl = asString(latestVersion?.json_url);
  if (!jsonUrl) {
    throw new Error(`设计图 ${imageId} 缺少 json_url`);
  }
  const sketch = await requestJson(jsonUrl, { timeoutMs: 60000 });
  return {
    document_info: documentInfo,
    json_url: jsonUrl,
    sketch,
  };
}

async function fetchBuffer(urlString) {
  const response = await fetch(urlString, {
    headers: {
      Accept: "*/*",
      Referer: config.baseUrl,
      "User-Agent": config.userAgent,
      ...(config.cookie ? { Cookie: config.cookie } : {}),
    },
    redirect: "follow",
  });

  if (!response.ok) {
    throw new Error(`下载资源失败: ${response.status} ${response.statusText}`);
  }

  const arrayBuffer = await response.arrayBuffer();
  return {
    buffer: Buffer.from(arrayBuffer),
    contentType: response.headers.get("content-type") || "",
    finalUrl: response.url,
  };
}

function resolveLink(rawLink) {
  const trimmed = String(rawLink || "").trim();
  if (!trimmed) {
    throw new Error("link 不能为空");
  }

  const url = new URL(trimmed, config.baseUrl);
  const hash = url.hash.startsWith("#") ? url.hash.slice(1) : url.hash;
  let route = url.pathname;
  let query = Object.fromEntries(url.searchParams.entries());
  if (hash) {
    const [hashRoute, hashQuery = ""] = hash.split("?", 2);
    route = hashRoute || route;
    query = Object.fromEntries(new URLSearchParams(hashQuery).entries());
  }
  return {
    raw_link: trimmed,
    normalized_url: url.toString(),
    host: url.host,
    pathname: route,
    query,
    hash: hash,
    link_type: inferLinkType(url),
    project_id: query.pid || query.project_id || "",
    team_id: query.tid || query.teamId || query.team_id || "",
    doc_id: query.docId || query.image_id || "",
    version_id: query.versionId || "",
  };
}

