        sliceResult.slices.forEach((slice, sliceIndex) => {
          if (scaleKeys.length > 0 && isRecord(slice.scale_urls)) {
            scaleKeys.forEach((scaleKey) => {
              const sourceUrl = asString(slice.scale_urls[scaleKey]);
              if (!sourceUrl) {
                return;
              }
              enqueueDownload(
                sourceUrl,
                buildExportFilename(
                  slice.download_url || sourceUrl,
                  `slice_${sliceIndex + 1}`,
                  scaleKey,
                ),
                {
                  kind: "slice",
                  scale_key: scaleKey,
                  page_id: design.id,
                  page_name: design.name,
                  slice_id: slice.id || "",
                  slice_name: slice.name || "",
                  layer_path: slice.layer_path || "",
                  logical_size: slice.logical_size || null,
                },
              );
            });
            return;
          }
          const sourceUrl = asString(slice.download_url);
          if (!sourceUrl) {
            return;
          }
          enqueueDownload(
            sourceUrl,
            sanitizeFilename(filenameFromUrl(sourceUrl, `slice_${sliceIndex + 1}`)),
            {
              kind: "slice",
              scale_key: "raw",
              page_id: design.id,
              page_name: design.name,
              slice_id: slice.id || "",
              slice_name: slice.name || "",
              layer_path: slice.layer_path || "",
              logical_size: slice.logical_size || null,
            },
          );
        });
        if (downloadQueue.length < limit) {
          extractAssetUrlsFromSketch(sketchResult.sketch).forEach((assetUrl, assetIndex) => {
            enqueueDownload(assetUrl, sanitizeFilename(filenameFromUrl(assetUrl, `asset_${assetIndex + 1}`)), {
              kind: "raw_asset",
              page_id: design.id,
              page_name: design.name,
            });
          });
        }
      } catch {
        // 某些设计图没有 sketch json，保留封面图即可
      }
    }

    coverQueue.forEach((task) => enqueueDownload(task.source_url, task.filename, task));

    await fs.mkdir(outputDir, { recursive: true });

    const downloaded = [];
    for (const task of downloadQueue.slice(0, limit)) {
      const fetched = await fetchBuffer(task.source_url);
      const filename = task.filename || sanitizeFilename(filenameFromUrl(fetched.finalUrl, `asset_${downloaded.length + 1}`));
      const targetPath = path.join(outputDir, filename);
      await fs.writeFile(targetPath, fetched.buffer);
      downloaded.push({
        source_url: task.source_url,
        final_url: fetched.finalUrl,
        filename,
        content_type: fetched.contentType,
        path: targetPath,
        size: fetched.buffer.byteLength,
        kind: task.kind || "asset",
        scale_key: task.scale_key || "",
        page_id: task.page_id || "",
        page_name: task.page_name || "",
        slice_id: task.slice_id || "",
        slice_name: task.slice_name || "",
        layer_path…75 chars truncated…     });
    }

    const manifestPath = path.join(outputDir, "lanhu-assets-manifest.json");
    await fs.writeFile(
      manifestPath,
      JSON.stringify(
        {
          link: rawLink,
          package_name: options.packageName || "",
          generated_at: new Date().toISOString(),
          preset,
          asset_count: downloaded.length,
          assets: downloaded,
        },
        null,
        2,
      ),
      "utf-8",
    );

    return {
      output_dir: outputDir,
      manifest_path: manifestPath,
      downloaded,
      inspected: inspectedResult.inspected,
    };
  }

  async function inspectPageDetail(rawLink, options = {}) {
    const resolved = resolveLink(rawLink);
    if (!resolved.project_id || !resolved.team_id) {
      throw new Error("蓝湖链接里缺少 pid 或 tid");
    }

    const projectImages = await getProjectImages(resolved.project_id, resolved.team_id);
    const selectedPackage = options.packageName ? pickPackage(projectImages.entries, options.packageName) : { anchor: null, region: null, designs: [] };
    const candidates = selectedPackage.designs.length > 0
      ? selectedPackage.designs
      : projectImages.entries.filter((entry) => isDesignCandidate(entry, ""));
    const selectedPage = pickDesignEntry(candidates, options);

    if (!selectedPage) {
      throw new Error("没有找到匹配的设计页");
    }

    const sketchResult = await getSketchJson(selectedPage.id, resolved.team_id, resolved.project_id);
    const details = extractPageDesignDetails(sketchResult.sketch);
    const sliceResult = extractSlicesFromSketch(sketchResult.sketch, true);

    return {
      project_name: projectImages.project_name,
      package_name: options.packageName || "",
      selected_package: selectedPackage.anchor
        ? {
            anchor: {
              id: selectedPackage.anchor.id,
              name: selectedPackage.anchor.name,
            },
            region: selectedPackage.region
              ? {
                  left: selectedPackage.region.left,
                  top: selectedPackage.region.top,
                  right: selectedPackage.region.right,
                  bottom: selectedPackage.region.bottom,
                }
              : null,
          }
        : null,
      page: {
        id: selectedPage.id,
        name: selectedPage.name,
        index: candidates.findIndex((entry) => entry.id === selectedPage.id),
        x: selectedPage.x,
        y: selectedPage.y,
        width: selectedPage.width,
        height: selectedPage.height,
        cover_url: selectedPage.url,
        json_url: sketchResult.json_url,
        artboard: details.artboard,
      },
      resources: {
        cover_url: selectedPage.url,
        asset_count: details.asset_urls.length,
        asset_urls: details.asset_urls,
        slice_scale: sliceResult.slice_scale,
        slice_count: sliceResult.slices.length,
        slices: sliceResult.slices.slice(0, 120),
      },
      styles: details.styles,
      spacing_hints: details.spacing_hints,
      text_samples: details.text_samples,
    };
  }

  async function summarizeForIosPack(rawLink, preferredFeatures = [], packageName = "") {
    const { inspected } = await inspectLink(rawLink, { packageName });
    const featureNames = unique(
      preferredFeatures.length > 0
        ? preferredFeatures
        : packageName && inspected.selected_package
          ? inspected.selected_package.designs.map((entry) => entry.name)
          : inspected.tab_candidates,
    );
    const pageNames = unique(inspected.page_names).slice(0, 20);
    const designSummary = [
      inspected.project_name ? `项目：${inspected.project_name}` : "",
      packageName ? `当前包：${packageName}` : "",
      featureNames.length ? `候选功能：${featureNames.join("、")}` : "",
      pageNames.length ? `页面线索：${pageNames.join("、")}` : "",
      inspected.asset_urls.length ? `资源数量：${inspected.asset_urls.length}` : "",
    ].filter(Boolean).join("；");

    return {
      project_hint: inspected.project_name || "",
      package_name: packageName || "",
      feature_names: featureNames,
      page_names: pageNames,
      tab_candidates: inspected.tab_candidates.slice(0, 8),
      asset_count: inspected.asset_urls.length,
      asset_preview: inspected.asset_urls.slice(0, 20),
      design_summary: designSummary,
      notes: [
        packageName && inspected.selected_package
          ? `已用包标签 ${packageName} 作为锚点筛出附近设计图`
          : "当前未指定包名，返回的是项目级设计图线索",
        "资源结果适合作为后续自动补资源和人工核对的输入",
        "切图下载默认支持 ios_all，可直接落地为 name.png / name@2x.png / name@3x.png",
      ],
    };
  }

  return {
    config,
    downloadAssets,
    inspectPageDetail,
    getProjectImages,
    getSketchJson,
    inspectLink,
    resolveLink,
    summarizeForIosPack,
  };
}

