export function summarizeForIosPack(inspected, preferredFeatures = []) {
  const normalizedPreferred = Array.from(new Set(preferredFeatures.map((item) => cleanText(item)).filter(Boolean)));
  const featureNames = normalizedPreferred.length > 0 ? normalizedPreferred : inspected.tab_candidates.slice(0, 5);
  const pageNames = inspected.page_names.slice(0, 20);
  const summaryLines = [
    inspected.document_title ? `文档标题：${inspected.document_title}` : "",
    featureNames.length ? `候选功能：${featureNames.join("、")}` : "",
    pageNames.length ? `页面线索：${pageNames.join("、")}` : "",
    inspected.asset_urls.length ? `资源数量：${inspected.asset_urls.length}` : "",
  ].filter(Boolean);

  return {
    project_hint: inspected.document_title || pageNames[0] || "",
    feature_names: featureNames,
    page_names: pageNames,
    tab_candidates: inspected.tab_candidates.slice(0, 8),
    asset_count: inspected.asset_urls.length,
    asset_preview: inspected.asset_urls.slice(0, 20),
    design_summary: summaryLines.join("；"),
    notes: [
      inspected.payload_count > 0 ? "已从页面嵌入 JSON 中提取设计结构" : "未发现嵌入 JSON，结果更多依赖 HTML 文本和资源链接",
      "资源结果适合作为后续自动补资源和人工核对的输入",
    ],
  };
}

