function parseLayoutBackground(layoutData) {
  const raw = asString(layoutData);
  const match = raw.match(PACKAGE_TAG_BACKGROUND_RE);
  return match ? `#${match[1]}` : "";
}

function normalizeEntry(item, index) {
  return {
    index: index + 1,
    id: asString(item.id),
    name: asString(item.name),
    type: asString(item.type),
    sub_type: asString(item.sub_type),
    width: asNumber(item.width),
    height: asNumber(item.height),
    x: asNumber(item.position_x) ?? asNumber(item.positions?.x),
    y: asNumber(item.position_y) ?? asNumber(item.positions?.y),
    url: asString(item.url),
    latest_version: asString(item.latest_version),
    dds_jump_status: asNumber(item.dds_jump_status),
    layout_data: asString(item.layout_data),
    background_color: parseLayoutBackground(item.layout_data),
    pinyin_name: asString(item.pinyinname),
    raw: item,
  };
}

function isPackageAnchor(entry, packageName) {
  if (!entry.name || !packageName || entry.name !== packageName) {
    return false;
  }
  return entry.type === "card" || !!entry.background_color;
}

function isDesignCandidate(entry, packageName) {
  if (!entry.url) {
    return false;
  }
  if (!entry.name || entry.name === packageName) {
    return false;
  }
  if (entry.type === "card") {
    return false;
  }
  if ((entry.width ?? 0) < 120 || (entry.height ?? 0) < 120) {
    return false;
  }
  return true;
}

function distance(left, right) {
  return Math.abs((left.x ?? 0) - (right.x ?? 0)) + Math.abs((left.y ?? 0) - (right.y ?? 0));
}

function isWithinVerticalBand(entry, top, bottom) {
  const entryTop = entry.y ?? 0;
  const entryBottom = entryTop + (entry.height ?? 0);
  return entryBottom >= top && entryTop <= bottom;
}

function isWithinHorizontalBand(entry, left, right) {
  const entryLeft = entry.x ?? 0;
  const entryRight = entryLeft + (entry.width ?? 0);
  return entryRight >= left && entryLeft <= right;
}

function findNextRightAnchor(anchors, anchor) {
  const anchorX = anchor.x ?? 0;
  const anchorY = anchor.y ?? 0;
  const verticalTolerance = Math.max(anchor.height ?? 0, 80) + 220;

  return anchors
    .filter((entry) => entry.id !== anchor.id && (entry.x ?? 0) > anchorX && Math.abs((entry.y ?? 0) - anchorY) <= verticalTolerance)
    .sort((left, right) => (left.x ?? 0) - (right.x ?? 0))[0] || null;
}

function findNextBottomAnchor(anchors, anchor, regionRight) {
  const anchorX = anchor.x ?? 0;
  const anchorY = anchor.y ?? 0;

  return anchors
    .filter(
      (entry) =>
        entry.id !== anchor.id &&
        (entry.y ?? 0) > anchorY &&
        (entry.x ?? 0) >= anchorX - 120 &&
        (entry.x ?? 0) <= regionRight,
    )
    .sort((left, right) => (left.y ?? 0) - (right.y ?? 0))[0] || null;
}

function buildPackageRegion(anchors, anchor) {
  const anchorX = anchor.x ?? 0;
  const anchorY = anchor.y ?? 0;
  const anchorWidth = anchor.width ?? 0;
  const anchorHeight = anchor.height ?? 0;
  const left = anchorX + Math.max(anchorWidth - 16, 100);
  const top = anchorY - Math.max(Math.round(anchorHeight * 1.5), 140);
  const rightAnchor = findNextRightAnchor(anchors, anchor);
  const provisionalRight = rightAnchor ? (rightAnchor.x ?? anchorX + 3600) - 120 : anchorX + 3600;
  const right = Math.max(left + 600, provisionalRight);
  const bottomAnchor = findNextBottomAnchor(anchors, anchor, right);
  const provisionalBottom = bottomAnchor ? (bottomAnchor.y ?? anchorY + 2400) - 140 : anchorY + 2400;
  const bottom = Math.max(top + 500, provisionalBottom);

  return {
    left,
    top,
    right,
    bottom,
    right_anchor: rightAnchor,
    bottom_anchor: bottomAnchor,
  };
}

function selectDesignsInPackageRegion(entries, anchors, anchor, packageName) {
  const region = buildPackageRegion(anchors, anchor);
  const designs = entries
    .filter((entry) => isDesignCandidate(entry, packageName))
    .map((entry) => ({
      ...entry,
      distance: distance(anchor, entry),
    }))
    .filter(
      (entry) =>
        isWithinHorizontalBand(entry, region.left, region.right) &&
        isWithinVerticalBand(entry, region.top, region.bottom) &&
        (entry.x ?? 0) >= region.left - 60,
    )
    .sort((left, right) => {
      const leftTopGap = Math.abs((left.y ?? 0) - (anchor.y ?? 0));
      const rightTopGap = Math.abs((right.y ?? 0) - (anchor.y ?? 0));
      if (leftTopGap !== rightTopGap) {
        return leftTopGap - rightTopGap;
      }
      if ((left.y ?? 0) !== (right.y ?? 0)) {
        return (left.y ?? 0) - (right.y ?? 0);
      }
      if ((left.x ?? 0) !== (right.x ?? 0)) {
        return (left.x ?? 0) - (right.x ?? 0);
      }
      return left.distance - right.distance;
    })
    .slice(0, 60);

  return {
    region,
    designs,
  };
}

function findPackageAnchors(entries) {
  return entries.filter((entry) => entry.type === "card" && entry.name && entry.background_color);
}

function pickPackage(entries, packageName) {
  const packageAnchors = findPackageAnchors(entries);
  const anchors = packageName ? entries.filter((entry) => isPackageAnchor(entry, packageName)) : [];
  const anchor = anchors[0] || null;
  if (!anchor) {
    return {
      anchor: null,
      region: null,
      designs: [],
    };
  }
  const selected = selectDesignsInPackageRegion(entries, packageAnchors, anchor, packageName);
  return {
    anchor,
    region: selected.region,
    designs: selected.designs,
  };
}

function extractAssetUrlsFromSketch(sketch) {
  const assetUrls = new Set();
  const visited = new Set();

  function walk(node) {
    if (node == null || visited.has(node)) {
      return;
    }
    if (Array.isArray(node)) {
      visited.add(node);
      node.forEach((item) => walk(item));
      return;
    }
    if (!isRecord(node)) {
      return;
    }

    visited.add(node);

    for (const key of SLICE_URL_KEYS) {
      const candidate = asString(node[key]);
      if (candidate.startsWith("http://") || candidate.startsWith("https://")) {
        assetUrls.add(candidate);
      }
    }

    for (const value of Object.values(node)) {
      walk(value);
    }
  }

  walk(sketch);
  return Array.from(assetUrls);
}

function jsRound(value) {
  return Math.floor(Number(value || 0) + 0.5);
}

function detectSliceScale(sketch) {
  const meta = isRecord(sketch?.meta) ? sketch.meta : {};
  const rawValue =
    asNumber(sketch?.sliceScale) ??
    asNumber(sketch?.exportScale) ??
    asNumber(meta?.sliceScale) ??
    2;

#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import subprocess
from pathlib import Path

from common import DEFAULT_LANHU_MCP_DIR, dump_json, split_feature_names


BRIDGE_SCRIPT = r"""
import { pathToFileURL } from "url";

const payload = JSON.parse(process.env.LANHU_BRIDGE_PAYLOAD || "{}");
const clientModuleUrl = pathToFileURL(process.env.LANHU_CLIENT_PATH).href;
const { createLanhuClient } = await import(clientModuleUrl);

const client = createLanhuClient({
  baseUrl: process.env.LANHU_BASE_URL || "https://lanhuapp.com",
  ddsBaseUrl: process.env.LANHU_DDS_BASE_URL || "https://dds.lanhuapp.com",
  cookie: process.env.LANHU_COOKIE || "",
  ddsCookie: process.env.DDS_COOKIE || process.env.LANHU_COOKIE || "",
  outputDir: process.env.LANHU_OUTPUT_DIR || "./downloads",
  requestTimeoutMs: Number.parseInt(process.env.LANHU_REQUEST_TIMEOUT_MS || "30000", 10) || 30000,
  userAgent: process.env.LANHU_USER_AGENT || "ios-pack-factory/lanhu-bridge",
});

const inspected = await client.inspectLink(payload.link, { packageName: payload.packageName || "" });
const summary = await client.summarizeForIosPack(payload.link, payload.preferredFeatures || [], payload.packageName || "");
const candidatePages = inspected.inspected.selected_package?.designs || [];

function pickSelectedPages() {
  const pageNames = Array.isArray(payload.pageNames) ? payload.pageNames.filter(Boolean) : [];
  const seenIds = new Set();
  const result = [];

  const append = (entry) => {
    if (!entry || seenIds.has(entry.id)) {
      return;
    }
    seenIds.add(entry.id);
    result.push(entry);
  };

  for (const pageName of pageNames) {
    const exact = candidatePages.find((entry) => entry.name === pageName);
    if (exact) {
      append(exact);
      continue;
    }
    const fuzzy = candidatePages.find((entry) => entry.name.includes(pageName));
    append(fuzzy);
  }

  const limit = Number.isInteger(payload.pageLimit) && payload.pageLimit > 0 ? payload.pageLimit : 4;
  for (const entry of candidatePages) {
    if (result.length >= limit) {
      break;
    }
    append(entry);
  }
  return result;
}

const selectedPages = pickSelectedPages();
const pageDetails = [];
for (const entry of selectedPages) {
  const detail = await client.inspectPageDetail(payload.link, {
    packageName: payload.packageName || "",
    pageId: entry.id,
  });
  pageDetails.push(detail);
}

console.log(JSON.stringify({
  project_name: inspected.inspected.project_name || "",
  package_name: payload.packageName || "",
  package_anchor: inspected.inspected.selected_package?.anchor || null,
  package_region: inspected.inspected.selected_package?.region || null,
  package_page_count: candidatePages.length,
  package_page_names: candidatePages.map((entry) => entry.name),
  summary,
  pages: pageDetails,
}, null, 2));
"""


def extract_lanhu_context(
    *,
    link: str,
    package_name: str,
    preferred_features: list[str] | None = None,
    page_limit: int = 4,
    page_names: list[str] | None = None,
    lanhu_mcp_dir: Path = DEFAULT_LANHU_MCP_DIR,
) -> dict:
    normalized_link = str(link).strip()
    normalized_package_name = str(package_name).strip()
    if not normalized_link:
        raise ValueError("lanhu_link 不能为空")
    if not normalized_package_name:
        raise ValueError("lanhu_package_name 不能为空")
    if not os.environ.get("LANHU_COOKIE", "").strip():
        raise RuntimeError("缺少 LANHU_COOKIE，无法读取蓝湖设计数据")

    lanhu_client_path = (lanhu_mcp_dir / "src" / "lanhu-client.js").resolve()
    if not lanhu_client_path.is_file():
        raise FileNotFoundError(f"未找到 lanhu-client.js: {lanhu_client_path}")

    payload = {
        "link": normalized_link,
        "packageName": normalized_package_name,
        "preferredFeatures": preferred_features or [],
        "pageLimit": page_limit,
        "pageNames": page_names or [],
    }

    env = os.environ.copy()
    env["LANHU_BRIDGE_PAYLOAD"] = json.dumps(payload, ensure_ascii=False)
    env["LANHU_CLIENT_PATH"] = str(lanhu_client_path)

    completed = subprocess.run(
        ["node", "--input-type=module", "-e", BRIDGE_SCRIPT],
        capture_output=True,
        text=True,
        check=True,
        env=env,
    )
    return json.loads(completed.stdout)


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="读取蓝湖当前包的设计上下文，输出包级摘要和页面级样式详情")
    parser.add_argument("--link", required=True, help="蓝湖项目链接")
    parser.add_argument("--package-name", required=True, help="黄色标签对应的当前包名")
    parser.add_argument("--preferred-features", nargs="*", default=[], help="可选功能名，传给蓝湖摘要层")
    parser.add_argument("--page-limit", type=int, default=4, help="默认提取前几页详情")
