#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import subprocess
from pathlib import Path

from common import DEFAULT_LANHU_MCP_DIR, dump_json, split_feature_names


BRIDGE_SCRIPT = r"""
import { pathToFileURL } from "url";

const payload = JSON.parse(process.env.LANHU_BRIDGE_PAYLOAD || "{}");
const clientModuleUrl = pathToFileURL(process.env.LANHU_CLIENT_PATH).href;
const { createLanhuClient } = await import(clientModuleUrl);

const client = createLanhuClient({
  baseUrl: process.env.LANHU_BASE_URL || "https://lanhuapp.com",
  ddsBaseUrl: process.env.LANHU_DDS_BASE_URL || "https://dds.lanhuapp.com",
  cookie: process.env.LANHU_COOKIE || "",
  ddsCookie: process.env.DDS_COOKIE || process.env.LANHU_COOKIE || "",
  outputDir: process.env.LANHU_OUTPUT_DIR || "./downloads",
  requestTimeoutMs: Number.parseInt(process.env.LANHU_REQUEST_TIMEOUT_MS || "30000", 10) || 30000,
  userAgent: process.env.LANHU_USER_AGENT || "ios-pack-factory/lanhu-bridge",
});

const inspected = await client.inspectLink(payload.link, { packageName: payload.packageName || "" });
const summary = await client.summarizeForIosPack(payload.link, payload.preferredFeatures || [], payload.packageName || "");
const candidatePages = inspected.inspected.selected_package?.designs || [];

function pickSelectedPages() {
  const pageNames = Array.isArray(payload.pageNames) ? payload.pageNames.filter(Boolean) : [];
  const seenIds = new Set();
  const result = [];

  const append = (entry) => {
    if (!entry || seenIds.has(entry.id)) {
      return;
    }
    seenIds.add(entry.id);
    result.push(entry);
  };

  for (const pageName of pageNames) {
    const exact = candidatePages.find((entry) => entry.name === pageName);
    if (exact) {
      append(exact);
      continue;
    }
    const fuzzy = candidatePages.find((entry) => entry.name.includes(pageName));
    append(fuzzy);
  }

  const limit = Number.isInteger(payload.pageLimit) && payload.pageLimit > 0 ? payload.pageLimit : 4;
  for (const entry of candidatePages) {
    if (result.length >= limit) {
      break;
    }
    append(entry);
  }
  return result;
}

const selectedPages = pickSelectedPages();
const pageDetails = [];
for (const entry of selectedPages) {
  const detail = await client.inspectPageDetail(payload.link, {
    packageName: payload.packageName || "",
    pageId: entry.id,
  });
  pageDetails.push(detail);
}

console.log(JSON.stringify({
  project_name: inspected.inspected.project_name || "",
  package_name: payload.packageName || "",
  package_anchor: inspected.inspected.selected_package?.anchor || null,
  package_region: inspected.inspected.selected_package?.region || null,
  package_page_count: candidatePages.length,
  package_page_names: candidatePages.map((entry) => entry.name),
  summary,
  pages: pageDetails,
}, null, 2));
"""


def extract_lanhu_context(
    *,
    link: str,
    package_name: str,
    preferred_features: list[str] | None = None,
    page_limit: int = 4,
    page_names: list[str] | None = None,
    lanhu_mcp_dir: Path = DEFAULT_LANHU_MCP_DIR,
) -> dict:
    normalized_link = str(link).strip()
    normalized_package_name = str(package_name).strip()
    if not normalized_link:
        raise ValueError("lanhu_link 不能为空")
    if not normalized_package_name:
        raise ValueError("lanhu_package_name 不能为空")
    if not os.environ.get("LANHU_COOKIE", "").strip():
        raise RuntimeError("缺少 LANHU_COOKIE，无法读取蓝湖设计数据")

    lanhu_client_path = (lanhu_mcp_dir / "src" / "lanhu-client.js").resolve()
    if not lanhu_client_path.is_file():
        raise FileNotFoundError(f"未找到 lanhu-client.js: {lanhu_client_path}")

    payload = {
        "link": normalized_link,
        "packageName": normalized_package_name,
        "preferredFeatures": preferred_features or [],
        "pageLimit": page_limit,
        "pageNames": page_names or [],
    }

    env = os.environ.copy()
    env["LANHU_BRIDGE_PAYLOAD"] = json.dumps(payload, ensure_ascii=False)
    env["LANHU_CLIENT_PATH"] = str(lanhu_client_path)

    completed = subprocess.run(
        ["node", "--input-type=module", "-e", BRIDGE_SCRIPT],
        capture_output=True,
        text=True,
        check=True,
        env=env,
    )
    return json.loads(completed.stdout)


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="读取蓝湖当前包的设计上下文，输出包级摘要和页面级样式详情")
    parser.add_argument("--link", required=True, help="蓝湖项目链接")
    parser.add_argument("--package-name", required=True, help="黄色标签对应的当前包名")
    parser.add_argument("--preferred-features", nargs="*", default=[], help="可选功能名，传给蓝湖摘要层")
    parser.add_argument("--page-limit", type=int, default=4, help="默认提取前几页详情")
    parser.add_argument("--page-names", nargs="*", default=[], help="优先提取的页面名")
    parser.add_argument("--lanhu-mcp-dir", default=str(DEFAULT_LANHU_MCP_DIR), help="本地 lanhu-mcp 目录")
    return parser


def main() -> None:
    parser = build_parser()
    args = parser.parse_args()
    result = extract_lanhu_context(
        link=args.link,
        package_name=args.package_name,
        preferred_features=split_feature_names(args.preferred_features),
        page_limit=args.page_limit,
        page_names=split_feature_names(args.page_names),
        lanhu_mcp_dir=Path(args.lanhu_mcp_dir).resolve(),
    )
    print(dump_json(result))


if __name__ == "__main__":
    main()

